import{_ as o,a as t}from"./chunks/sofly-icon.BK_fG20o.js";import{_ as a,o as r,c as i,a2 as s}from"./chunks/framework.Crpw6aS5.js";const n="/assets/01-home-screen.BWKuENFh.png",l="/assets/sofly-screenshot.DyLc9Yiw.png",b=JSON.parse('{"title":"GPS Remote for Osmo Action","description":"Notes on GPS Remote for Osmo Action.","frontmatter":{"title":"GPS Remote for Osmo Action","description":"Notes on GPS Remote for Osmo Action."},"headers":[],"relativePath":"software-engineering/android-app-development/play-google-com-gps-remote-for-osmo-action.md","filePath":"software-engineering/android-app-development/play-google-com-gps-remote-for-osmo-action.md"}'),c={name:"software-engineering/android-app-development/play-google-com-gps-remote-for-osmo-action.md"};function p(d,e,m,h,g,u){return r(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="gps-remote-for-osmo-action" tabindex="-1">GPS Remote for Osmo Action <a class="header-anchor" href="#gps-remote-for-osmo-action" aria-label="Permalink to &quot;GPS Remote for Osmo Action&quot;">​</a></h1><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: webpage</li><li>Origin: <a href="https://play.google.com/store/apps/details?id=com.devsdev.gpsremote" target="_blank" rel="noreferrer">Google Play — GPS Remote for Osmo Action</a></li><li>Imported: 2025-06-19</li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><p><img src="'+o+'" alt="GPS Remote for Osmo Action icon"></p><p><strong>Developer:</strong> Devin Norgarb · <strong>Category:</strong> Photography · <strong>Updated:</strong> Jun 8, 2026</p><blockquote><p>This app is made by an independent developer and is not affiliated with, endorsed by, or sponsored by DJI. Osmo, DJI, and related names are trademarks of their respective owners. The app is not licensed by DJI. It communicates with cameras you own using protocol interoperability for GPS push and basic remote controls.</p></blockquote><h3 id="gps-remote-for-your-osmo-action-360" tabindex="-1">GPS remote for your Osmo Action &amp; 360 <a class="header-anchor" href="#gps-remote-for-your-osmo-action-360" aria-label="Permalink to &quot;GPS remote for your Osmo Action &amp; 360&quot;">​</a></h3><p>Use your phone as a GPS source and lightweight Bluetooth remote for supported Osmo cameras — no extra hardware required. Connect directly over BLE, push your phone&#39;s location to the camera for geotagged footage, and control recording from your pocket.</p><h3 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h3><ul><li>Direct Bluetooth connection to your Osmo camera</li><li>GPS push from your phone&#39;s location to the camera</li><li>Basic remote controls while connected: start/stop recording, quick switch, sleep</li><li>Live camera status updates on the home screen</li><li>Background GPS push with a persistent notification while connected (Android)</li><li>Simple step-by-step flow: scan, connect, send location</li></ul><h3 id="supported-cameras" tabindex="-1">Supported cameras <a class="header-anchor" href="#supported-cameras" aria-label="Permalink to &quot;Supported cameras&quot;">​</a></h3><p>Works with <strong>Osmo Action 4</strong>, <strong>Osmo Action 5 Pro</strong>, <strong>Osmo Action 6</strong>, and <strong>Osmo 360</strong>. Other models are not supported unless listed in a future update.</p><h3 id="getting-started" tabindex="-1">Getting started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting started&quot;">​</a></h3><ol><li>Install on a physical Android phone (Bluetooth requires a native install).</li><li>Grant Nearby devices and Location when prompted.</li><li>Tap <strong>Scan for Osmo Action &amp; 360</strong> and select your camera.</li><li>On first pairing, confirm the verify code on the camera screen.</li><li>Tap <strong>Send location to camera</strong> to start GPS push.</li><li>Use remote controls while connected; tap <strong>Disconnect</strong> when finished.</li></ol><p>For reliable GPS push while the app is in the background, allow notifications and optionally disable battery optimization for this app when prompted.</p><h3 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h3><ul><li>Android phone with Bluetooth Low Energy</li><li>A supported Osmo camera you own</li><li>Location and Bluetooth permissions while using the app</li></ul><h3 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to &quot;Privacy&quot;">​</a></h3><p>Location data is used only to send GPS to your connected camera. It is not sold or used for advertising.</p><h3 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h3><p>This is a third-party utility, not an official DJI or Mimo app. Features depend on your camera model and firmware. GPS push and remote commands are best-effort; behavior may vary by device and Android version.</p><h3 id="figures" tabindex="-1">Figures <a class="header-anchor" href="#figures" aria-label="Permalink to &quot;Figures&quot;">​</a></h3><p><img src="'+n+'" alt="GPS Remote home screen"></p><hr><h2 id="related-app-—-sofly" tabindex="-1">Related app — SoFly <a class="header-anchor" href="#related-app-—-sofly" aria-label="Permalink to &quot;Related app — SoFly&quot;">​</a></h2><p><img src="'+t+'" alt="SoFly icon"></p><p><strong>Play Store:</strong> <a href="https://play.google.com/store/apps/details?id=flight.track" target="_blank" rel="noreferrer">SoFly — flight tracking &amp; logging</a> · <strong>Category:</strong> Maps &amp; Navigation · <strong>Updated:</strong> Jun 18, 2026</p><p>Discover SoFly — flight tracking and logging for pilots, aviation enthusiasts, and adventurers. Record flights with GPS tracking, aircraft details, timestamps, and custom notes. Sync across Android and desktop via OAuth (Google, GitHub). Export paths as CSV or database-friendly structures. End-to-end encryption in sync; privacy-focused design.</p><p><img src="'+l+'" alt="SoFly screenshot"></p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li><strong>GPS Remote</strong> pushes phone GPS to Osmo Action 4/5 Pro/6 and Osmo 360 over BLE, with basic recording controls.</li><li><strong>SoFly</strong> is a separate published app for flight logging, cross-device sync, and track export.</li><li>Both apps are by the same developer; neither is affiliated with DJI (GPS Remote) or third-party aviation vendors (SoFly).</li><li>Store links: <a href="https://play.google.com/store/apps/details?id=com.devsdev.gpsremote" target="_blank" rel="noreferrer">GPS Remote</a> · <a href="https://play.google.com/store/apps/details?id=flight.track" target="_blank" rel="noreferrer">SoFly</a></li></ul>',32)])])}const S=a(c,[["render",p]]);export{b as __pageData,S as default};
